#include<bits/stdc++.h>
using namespace std;
map<int,int> mp;
int sum[510][510],tot,val[510][510],p[1000010],ans[60010],n,q;
vector<pair<int,int>> vec[1000010];
int k[60010],ax[60010],ay[60010],bx[60010],by[60010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int y,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        for(int j=y;j<=n;j+=lowbit(j))
        {
            sum[i][j]+=v;
        }
    }
}
int query(int x,int y)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        for(int j=y;j>=1;j-=lowbit(j))
        {
            ans+=sum[i][j];
        }
    }
    return ans;
}
int getsum(int ax,int ay,int bx,int by)
{
    return query(bx,by)-query(ax-1,by)-query(bx,ay-1)+query(ax-1,ay-1);
}
void dfs(int l,int r,vector<int> v)
{
    if(l==r)
    {
        for(int i:v)
        {
            ans[i]=l;
        }
        return;
    }
    int mid=(l+r)>>1;
    for(int i=l;i<=mid;i++)
    {
        for(auto j:vec[i])
        {
            add(j.first,j.second,1);
        }
    }
    vector<int> vl,vr;
    for(int i:v)
    {
        if(getsum(ax[i],ay[i],bx[i],by[i])>=k[i])
        {
            vl.push_back(i);
        }
        else
        {
            vr.push_back(i);
        }
    }
    dfs(mid+1,r,vr);
    for(int i=l;i<=mid;i++)
    {
        for(auto j:vec[i])
        {
            add(j.first,j.second,-1);
        }
    }
    dfs(l,mid,vl);
}
int main()
{
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            scanf("%d",&val[i][j]);
            p[++tot]=val[i][j];
        }
    }
    sort(p+1,p+1+tot);
    tot=unique(p+1,p+1+tot)-p-1;
    for(int i=1;i<=tot;i++)
    {
        mp[p[i]]=i;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            vec[mp[val[i][j]]].push_back({i,j});
        }
    }
    vector<int> tmp;
    for(int i=1;i<=q;i++)
    {
        scanf("%d%d%d%d%d",&ax[i],&ay[i],&bx[i],&by[i],&k[i]);
        tmp.push_back(i);
    }
    dfs(1,tot,tmp);
    for(int i=1;i<=q;i++)
    {
        printf("%d\n",p[ans[i]]);
    }
    return 0;
}
